import{_ as e,a,b as d,c as r,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as l,o as i,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const T=JSON.parse('{"title":"Telegram 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/telegram.md","filePath":"cn/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"cn/upload/telegram.md"};function c(p,t,m,b,g,u){return i(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="telegram-渠道添加说明" tabindex="-1">Telegram 渠道添加说明 <a class="header-anchor" href="#telegram-渠道添加说明" aria-label="Permalink to &quot;Telegram 渠道添加说明&quot;">​</a></h1><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>Telegram 账号</td><td>用于创建机器人和频道。</td></tr><tr><td><code>@BotFather</code></td><td>用于申请 Telegram 机器人。</td></tr><tr><td>一个频道</td><td>作为 Telegram 存储渠道使用。</td></tr><tr><td><code>@userinfobot</code></td><td>用于查询频道 <code>Chat ID</code>。</td></tr></tbody></table><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><ol><li>进入系统配置。</li><li>打开上传设置。</li><li>点击右上角“添加渠道”。</li><li>选择 <code>Telegram</code>。</li></ol><h2 id="字段说明" tabindex="-1">字段说明 <a class="header-anchor" href="#字段说明" aria-label="Permalink to &quot;字段说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>作用</th><th>是否必填</th></tr></thead><tbody><tr><td>渠道名称</td><td>用于区分当前渠道，例如“Telegram 主频道”。</td><td>必填</td></tr><tr><td>Active</td><td>控制当前渠道是否启用。</td><td>建议开启</td></tr><tr><td>Bot Token</td><td>Telegram 机器人令牌。</td><td>必填</td></tr><tr><td>Session ID（Chat ID）</td><td>Telegram 频道 ID。</td><td>必填</td></tr><tr><td>Relay Proxy URL（可选）</td><td>仅在访问 Telegram 不稳定时使用，请填写完整代理地址（包含 <code>https://</code>）。</td><td>选填</td></tr><tr><td>Remark</td><td>渠道备注信息，便于后续管理。</td><td>选填</td></tr></tbody></table><h2 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h2><h3 id="_1-创建-telegram-机器人" tabindex="-1">1. 创建 Telegram 机器人 <a class="header-anchor" href="#_1-创建-telegram-机器人" aria-label="Permalink to &quot;1. 创建 Telegram 机器人&quot;">​</a></h3><ol><li>打开 Telegram，搜索 <code>@BotFather</code>。</li><li>进入对话后点击 <code>Start</code>。</li><li>发送 <code>/newbot</code>。</li><li>按提示填写机器人名称。</li><li>按提示填写机器人用户名。用户名通常需要以 <code>bot</code> 结尾。</li><li>创建完成后，<code>@BotFather</code> 会返回一串机器人令牌。</li></ol><p>这串令牌就是系统配置中需要填写的 <code>Bot Token</code>。</p><p><img src="'+e+'" alt="保存机器人令牌" loading="lazy"></p><h3 id="_2-创建频道" tabindex="-1">2. 创建频道 <a class="header-anchor" href="#_2-创建频道" aria-label="Permalink to &quot;2. 创建频道&quot;">​</a></h3><ol><li>在 Telegram 中点击“新建频道”。</li><li>填写频道名称。</li><li>完成频道创建。</li></ol><p>公开频道和私有频道都可以使用。</p><p><img src="'+a+'" alt="新建频道" loading="lazy"></p><h3 id="_3-将机器人加入频道" tabindex="-1">3. 将机器人加入频道 <a class="header-anchor" href="#_3-将机器人加入频道" aria-label="Permalink to &quot;3. 将机器人加入频道&quot;">​</a></h3><ol><li>进入刚创建好的频道。</li><li>打开频道设置。</li><li>添加成员或管理员。</li><li>搜索刚才创建的机器人用户名。</li><li>将机器人加入频道。</li></ol><p>建议直接授予机器人管理员权限，后续发图和发文件会更稳定。</p><p><img src="'+d+'" alt="邀请机器人进频道里" loading="lazy"></p><h3 id="_4-通过-user-info-•-get-id-•-idbot-获取频道-id" tabindex="-1">4. 通过 User Info • Get ID • IDbot 获取频道 ID <a class="header-anchor" href="#_4-通过-user-info-•-get-id-•-idbot-获取频道-id" aria-label="Permalink to &quot;4. 通过 User Info • Get ID • IDbot 获取频道 ID&quot;">​</a></h3><ol><li>在 Telegram 中搜索 <code>@userinfobot</code>，其显示名称通常为 <code>User Info • Get ID • IDbot</code>。</li><li>打开对话并点击 <code>Start</code>。</li><li>在 bot 提供的选项中点击 <code>Channel</code>。</li><li>在消息列表里，选择对应频道发送给 <code>@userinfobot</code>。</li><li><code>@userinfobot</code> 返回结果后，复制其中 <code>Id: -100...</code> 这一串数字。</li></ol><p>这串以 <code>-100</code> 开头的数字，就是系统配置中需要填写的 <code>Session ID（Chat ID）</code>。</p><p><img src="'+r+'" alt="获取频道id" loading="lazy"></p><h3 id="_5-在系统中填写-telegram-渠道" tabindex="-1">5. 在系统中填写 Telegram 渠道 <a class="header-anchor" href="#_5-在系统中填写-telegram-渠道" aria-label="Permalink to &quot;5. 在系统中填写 Telegram 渠道&quot;">​</a></h3><p>回到系统配置弹窗后，按下表填写：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>填写内容</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>自定义渠道名称，例如 <code>Telegram主频道</code></td></tr><tr><td>Active</td><td>建议开启</td></tr><tr><td>Bot Token</td><td>从 <code>@BotFather</code> 获取的机器人令牌</td></tr><tr><td>Session ID（Chat ID）</td><td>从 <code>@userinfobot</code> 返回结果中复制的 <code>-100...</code> 数字</td></tr><tr><td>Relay Proxy URL（可选）</td><td>按需填写，格式例如 <code>https://your-tg-proxy.example.com</code></td></tr><tr><td>Remark</td><td>按需填写</td></tr></tbody></table><p>填写完成后点击保存。</p><p><img src="'+o+`" alt="编辑配置" loading="lazy"></p><h2 id="添加完成后怎么检查" tabindex="-1">添加完成后怎么检查 <a class="header-anchor" href="#添加完成后怎么检查" aria-label="Permalink to &quot;添加完成后怎么检查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>检查项</th><th>检查方式</th></tr></thead><tbody><tr><td>渠道卡片是否出现</td><td>保存后，上传设置页面应显示 Telegram 渠道卡片。</td></tr><tr><td>渠道是否能启用</td><td>开关应可正常开启。</td></tr><tr><td>配置信息是否已保存</td><td>详情页应能看到 Bot Token 和 Chat ID 已写入。</td></tr><tr><td>上传是否正常</td><td>上传一张测试图片，确认图片已进入目标 Telegram 频道。</td></tr></tbody></table><h2 id="一句话流程速查" tabindex="-1">一句话流程速查 <a class="header-anchor" href="#一句话流程速查" aria-label="Permalink to &quot;一句话流程速查&quot;">​</a></h2><div class="language-test vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">test</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>搜索 @BotFather 创建机器人</span></span>
<span class="line"><span>-&gt; 保存 Bot Token</span></span>
<span class="line"><span>-&gt; 创建频道</span></span>
<span class="line"><span>-&gt; 将机器人加入频道并授予管理员权限</span></span>
<span class="line"><span>-&gt; 搜索 @userinfobot 并点击 Channel</span></span>
<span class="line"><span>-&gt; 将频道中的任意一条消息转发给 @userinfobot</span></span>
<span class="line"><span>-&gt; 复制返回结果中的 Id: -100...</span></span>
<span class="line"><span>-&gt; 将 Bot Token 和 Chat ID 填入系统配置并保存</span></span></code></pre></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ol><li>Telegram 机器人介绍：<a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API：<a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const k=l(h,[["render",c]]);export{T as __pageData,k as default};
